-- Batch 1: Templates, Activities, Process Steps, Activity Process Map, Hazard Library
DELETE FROM templates;

DELETE FROM activity_types;

DELETE FROM process_steps;

DELETE FROM activity_process_map;

DELETE FROM hazard_library;

SELECT setval('templates_id_seq', COALESCE((SELECT MAX(id) FROM templates), 0) + 1, false);
SELECT setval('activity_types_id_seq', COALESCE((SELECT MAX(id) FROM activity_types), 0) + 1, false);
SELECT setval('process_steps_id_seq', COALESCE((SELECT MAX(id) FROM process_steps), 0) + 1, false);
SELECT setval('activity_process_map_id_seq', COALESCE((SELECT MAX(id) FROM activity_process_map), 0) + 1, false);
SELECT setval('hazard_library_id_seq', COALESCE((SELECT MAX(id) FROM hazard_library), 0) + 1, false);